#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int cmp_char(const void *a, const void *b) {
    return (*(const char *)a) - (*(const char *)b);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char buf[1005];
    while (T--) {
        if (scanf("%s", buf) != 1) break;
        int n = strlen(buf);
        // convert to ordinal values (1..26) stored as chars for sorting
        for (int i = 0; i < n; ++i) buf[i] = buf[i] - 'a' + 1;
        qsort(buf, n, sizeof(char), cmp_char);
        long long ans = 0;
        for (int i = 0; i < n; ++i) {
            ans += (long long)(i + 1) * (int)buf[i];
        }
        printf("%lld\n", ans);
    }
    return 0;
}

