#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--) {
        string s; cin>>s;
        vector<int> v;
        v.reserve(s.size());
        for(char c: s) v.push_back(c - 'a' + 1);
        sort(v.begin(), v.end());
        long long ans = 0;
        for(size_t i=0;i<v.size();++i) ans += (long long)(i+1) * v[i];
        cout << ans << '\n';
    }
    return 0;
}

